def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 30 + np.exp(-cap / 10) * 50 + np.sin(cap) * 20
        fluctuation = 0.0
        if usage > 6:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 50 * np.cos(cap * 2.0)
            else:
                base_priority -= 60 * usage
            for i in range(1, 6):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.9) * 30 / i
        elif 4 < usage <= 6:
            delta = usage - 4
            base_priority += 2500 * delta ** 2.1 + 300 * (1 - delta ** 0.4)
            for j in range(2, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.5)) * 28 / j
            if int(cap * 4) % 4 == 1:
                base_priority += 50 * np.tan(cap / 10)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 15 / k
                    if k % 4 == 1:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.3:
                        fluctuation += 25
            if cap % 3.1 < 0.6:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 3.1
            for m in range(1, 19):
                pwr = usage ** m
                if pwr < 0.55:
                    fluctuation += pwr * 20 / m
                    if m % 4 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 15 and usage > 2.7:
                        fluctuation += 22
            if cap % 1.7 < 0.45:
                base_priority += 40 * np.cos(cap * 2.4)
        elif 1.5 < usage <= 2:
            base_priority += 800 * (usage - 1.5) ** 4
            for n in range(1, 12):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 18 / n
                    if n % 2 == 0:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 14 / (n + 1)
                    if n == 10 and usage > 1.8:
                        fluctuation += 18
            if cap % 2.0 < 0.35:
                base_priority += 33 * np.sin(cap * 3.1)
        elif 1 < usage <= 1.5:
            base_priority += 600 * (1.5 - usage) ** 2.5
            for o in range(1, 20):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.4) * 20 / o
                if usage < 0.08 * o:
                    fluctuation -= 7 * o
            if cap < 0.2:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.0:
                base_priority += np.log1p(cap * 18) * 32
            else:
                base_priority += (cap % 7) * 26
        elif 0.75 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 2
            for p in range(1, 15):
                pwr = usage ** p
                fluctuation += (np.tanh(pwr * np.pi / 5) - 0.35) * 14 / p
                if usage < 0.05 * p:
                    fluctuation -= 9 * p
            if cap < 0.1:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.75:
                base_priority += np.log1p(cap * 17) * 29
            else:
                base_priority += (cap % 4) * 24
        else:
            base_priority += 310 * (1 - usage) ** 1.7
            for q in range(1, 22):
                pwr = usage ** q
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.2) * 16 / q
                if usage < 0.02 * q:
                    fluctuation -= 14 * q
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.1:
                base_priority += np.log1p(cap * 22) * 42
            else:
                base_priority += (cap % 8) * 33
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 85
            if usage > 0.8:
                priority += 105
            elif usage < 0.15:
                priority -= 60
                for r in range(1, 8):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.1:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1500) % (s + 5) == 1:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.14:
                priority -= 45
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.97:
                priority += 100
                for u in range(1, 6):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1100) % 29 == 0:
            proximity -= 14
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for v in range(1, 12):
            diff = abs(usage - v / 11)
            if diff < 0.018:
                proximity += 22 / v
            elif diff < 0.04:
                proximity += 14 / v
            else:
                proximity -= 5 / v
        for w in range(1, 10):
            mod_chk = int(cap * 1900) % (w + 11)
            if mod_chk == 0:
                proximity += w * 6
            elif mod_chk == 4:
                proximity -= w * 5
        for x in range(1, 6):
            mod_chk = int(usage * 1800) % (x + 7)
            if mod_chk == 0:
                proximity += 12 * x
            elif mod_chk == 4:
                proximity -= 9 * x
        priority += proximity
        if usage < 0.003:
            for y in range(1, 9):
                priority -= y * 15
        elif usage > 0.97:
            for z in range(1, 8):
                priority += z * 14
        if cap > 3.0:
            if cap % 1 < 0.04:
                priority += 55
            if (int(cap * 3000) % 29 == 0) and (usage > 0.75):
                priority += 75
            for aa in range(1, 7):
                if (int(cap * 720) % (aa + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 2.5e4
        if abs(priority) > 2.5e4:
            priority = np.sign(priority) * 2.5e4
        priorities[idx] = priority
    return priorities
